"""Views for the chat application."""

from django.http import HttpRequest, HttpResponse
from django.shortcuts import render


def chat_view(request: HttpRequest) -> HttpResponse:
    """Render the main chat SPA."""
    return render(request, "chat/index.html")

document.addEventListener('DOMContentLoaded', function() {
    const form = document.getElementById('chat-form');
    const input = document.getElementById('message-input');
    const sendButton = document.getElementById('send-button');
    const messagesContainer = document.getElementById('messages-container');

    let ws = null;
    let currentAssistantMessage = null;

    function connectWebSocket() {
        const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
        ws = new WebSocket(`${protocol}//${window.location.host}/ws/chat/`);

        ws.onopen = function() {
            console.log('WebSocket connected');
        };

        ws.onmessage = function(event) {
            const data = JSON.parse(event.data);

            if (data.type === 'token') {
                if (!currentAssistantMessage) {
                    currentAssistantMessage = createAssistantMessageElement();
                }
                const contentDiv = currentAssistantMessage.querySelector('.message-content');
                contentDiv.textContent += data.content;
                scrollToBottom();
            } else if (data.type === 'done') {
                currentAssistantMessage = null;
                enableInput();
            } else if (data.type === 'error') {
                showError(data.message);
                currentAssistantMessage = null;
                enableInput();
            }
        };

        ws.onclose = function() {
            console.log('WebSocket disconnected');
            setTimeout(connectWebSocket, 1000);
        };

        ws.onerror = function(error) {
            console.error('WebSocket error:', error);
        };
    }

    function createUserMessageElement(text) {
        const wrapper = document.createElement('div');
        wrapper.className = 'flex items-start space-x-3 justify-end';

        const content = document.createElement('div');
        content.className = 'bg-blue-500 text-white rounded-lg px-4 py-3';
        content.textContent = text;

        wrapper.appendChild(content);
        return wrapper;
    }

    function createAssistantMessageElement() {
        const wrapper = document.createElement('div');
        wrapper.className = 'flex items-start space-x-3';

        const avatar = document.createElement('div');
        avatar.className = 'w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-white text-sm font-medium flex-shrink-0';
        avatar.textContent = 'AI';

        const content = document.createElement('div');
        content.className = 'flex-1 bg-gray-100 rounded-lg px-4 py-3 text-gray-800 message-content';

        wrapper.appendChild(avatar);
        wrapper.appendChild(content);
        return wrapper;
    }

    function scrollToBottom() {
        const chatMessages = document.getElementById('chat-messages');
        chatMessages.scrollTop = chatMessages.scrollHeight;
    }

    function disableInput() {
        input.disabled = true;
        sendButton.disabled = true;
    }

    function enableInput() {
        input.disabled = false;
        sendButton.disabled = false;
        input.focus();
    }

    function showError(message) {
        const errorDiv = document.createElement('div');
        errorDiv.className = 'flex items-start space-x-3';
        errorDiv.innerHTML = `
            <div class="w-8 h-8 rounded-full bg-red-500 flex items-center justify-center text-white text-sm font-medium flex-shrink-0">!</div>
            <div class="flex-1 bg-red-50 border border-red-200 rounded-lg px-4 py-3 text-red-800 text-sm">
                Error: ${message}
            </div>
        `;
        messagesContainer.appendChild(errorDiv);
        scrollToBottom();
    }

    form.addEventListener('submit', function(e) {
        e.preventDefault();

        const message = input.value.trim();
        if (!message || !ws || ws.readyState !== WebSocket.OPEN) {
            return;
        }

        const userMessage = createUserMessageElement(message);
        messagesContainer.appendChild(userMessage);
        scrollToBottom();

        input.value = '';
        disableInput();

        ws.send(JSON.stringify({ message: message }));
    });

    connectWebSocket();
});

